import React, { useState } from "react";
import axios from "axios";

import districtOptions from "../data/district_options.json";
import commodityOptions from "../data/commodity_options.json";

const CropPriceLookup = () => {
    const [district, setDistrict] = useState("");
    const [commodity, setCommodity] = useState("");
    const [prices, setPrices] = useState(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const fetchPrices = async () => {
        if (!commodity || !district) {
            setError("Please select both commodity and district.");
            return;
        }

        setLoading(true);
        setError("");

        try {
            const response = await axios.post("http://localhost:5000/api/crops/getPrices", {
                Commodity: commodity,
                District: district,
            });
            setPrices(response.data);
        } catch (err) {
            setError("Failed to fetch price data.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="max-w-lg mx-auto p-6 bg-white shadow-lg rounded-lg border border-gray-200">
            <h2 className="text-2xl font-semibold text-gray-800 mb-4 text-center">Crop Price Lookup</h2>
            
            <div className="space-y-4">
                <select 
                    value={commodity} 
                    onChange={(e) => setCommodity(e.target.value)} 
                    className="w-full p-3 border rounded-lg text-gray-700 focus:ring focus:ring-blue-200"
                >
                    <option value="">Select Commodity</option>
                    {commodityOptions.map((item, index) => (
                        <option key={index} value={item}>{item}</option>
                    ))}
                </select>

                <select 
                    value={district} 
                    onChange={(e) => setDistrict(e.target.value)} 
                    className="w-full p-3 border rounded-lg text-gray-700 focus:ring focus:ring-blue-200"
                >
                    <option value="">Select District</option>
                    {districtOptions.map((item, index) => (
                        <option key={index} value={item}>{item}</option>
                    ))}
                </select>
            </div>
            
            <button 
                onClick={fetchPrices} 
                className="w-full mt-4 p-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition"
            >
                Get Prices
            </button>
            
            {loading && <p className="text-center mt-3 text-gray-600">Loading...</p>}
            {error && <p className="text-center mt-3 text-red-600">{error}</p>}
            
            {prices && (
                <div className="mt-6 p-4 bg-gray-100 rounded-lg">
                    <h3 className="text-lg font-medium text-gray-700">Price Details</h3>
                    <div className="mt-3 space-y-3">
                        {prices.map((data, index) => (
                            <div key={index} className="p-3 bg-white shadow-sm rounded-lg border">
                                <p><strong>Grade:</strong> {data.Grade}</p>
                                <p><strong>Min Price:</strong> {data["Min Price"]} ₹</p>
                                <p><strong>Max Price:</strong> {data["Max Price"]} ₹</p>
                                <p><strong>Modal Price:</strong> {data["Modal Price"]} ₹</p>
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
};

export default CropPriceLookup;
